318	export function determineSpecialTilePosition(game, group, formationType) {
319	    // For 4-tile formations, determine which of the 2 middle positions should get the special tile
320	    // based on where the last swap was made
321	    if (!game.lastSwapPosition) {
322	        // If no swap info, default to first middle position
323	        if (formationType === "block_4") {
324	            return group.intersections[0];
325	        } else {
326	            const middlePositions = calculateMiddlePositions(game, group.tiles);
327	            return middlePositions[0];
328	        }
329	    }
330	
331	    const swapPos = game.lastSwapPosition;
332	
333	    if (formationType === "block_4") {
334	        // For block formation, choose the intersection closest to swap position
335	        // First check if the swapped tile is one of the intersections
336	        const matchingIntersection = group.intersections.find(
337	            (pos) => pos.row === swapPos.row && pos.col === swapPos.col,
338	        );
339	        if (matchingIntersection) {
340	            return matchingIntersection;
341	        }
342	
